const body = $('Webhook - POST create-program').item.json.body;
const org_id = body.organization_id;
const program = body.program;

const DAY_INDEX = {
  monday: 1, tuesday: 2, wednesday: 3, thursday: 4,
  friday: 5, saturday: 6, sunday: 0
};

const startDate = new Date(program.start_date + 'T09:00:00Z');

const posts = (program.posts || []).map((post, idx) => {
  const weekOffset = (post.week - 1) * 7;
  const startDay = startDate.getDay(); // 0 = dimanche
  const targetDay = DAY_INDEX[post.day_of_week?.toLowerCase()] ?? 1;

  // Calculer le décalage en jours depuis le début du programme
  let dayDiff = targetDay - startDay;
  if (dayDiff < 0) dayDiff += 7;

  const postDate = new Date(startDate);
  postDate.setDate(postDate.getDate() + weekOffset + dayDiff);

  return {
    title: post.title,
    week: post.week,
    theme: post.theme || '',
    day_of_week: post.day_of_week || 'monday',
    scheduled_at: postDate.toISOString(),
    position_in_program: idx + 1
  };
});

return [{ json: { org_id, program, posts_with_dates: posts } }];

