const program_id = programRow.id;
const org_id = calcNode.org_id;
const postsWithDates = calcNode.posts_with_dates;

const supabaseUrl = $env.POSTPILOT_SUPABASE_URL;
const serviceKey = $env.POSTPILOT_SUPABASE_SERVICE_ROLE_KEY;

const createdPosts = [];
for (const post of postsWithDates) {
  const body = JSON.stringify({
    organization_id: org_id,
    program_id: program_id,
    title: post.title,
    content: '',
    status: 'waiting',
    scheduled_at: post.scheduled_at,
    publication_time: '09:00',
    position_in_program: post.position_in_program,
    platform_type: 'linkedin'
  });

  const res = await $helpers.httpRequest({
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/posts`,
    headers: {
      'apikey': $env.POSTPILOT_SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${serviceKey}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body,
    returnFullResponse: false
  });

  const created = Array.isArray(res) ? res[0] : res;
  createdPosts.push({ id: created.id, title: post.title, scheduled_at: post.scheduled_at });
}

return [{ json: { program: programRow, posts: createdPosts } }];
